+        .unwrap();
+        let rhs_mask = UFuncArray::new(vec![2, 1], vec![1.0, 0.0], DType::Bool).unwrap();
+        let rhs = MaskedArray {
+            data: rhs_data,
+            mask: Some(rhs_mask),
+            fill_value: 1e20,
+            hard_mask: false,
+        };
+
+        let result = lhs.elementwise_binary(&rhs, BinaryOp::Add).unwrap();
